--
-- Name: admin_get_user_metadata(uuid); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.admin_get_user_metadata(target_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
DECLARE
  caller_id UUID;
  caller_role TEXT;
  caller_email TEXT;
  target_metadata JSONB;
  target_email TEXT;
BEGIN
  caller_id := auth.uid();

  IF caller_id IS NULL THEN
    RAISE EXCEPTION 'Access denied - not authenticated';
  END IF;

  SELECT u.email, u.raw_user_meta_data->>'role'
  INTO caller_email, caller_role
  FROM auth.users u
  WHERE u.id = caller_id;

  IF caller_id IS DISTINCT FROM target_user_id
     AND caller_role NOT IN ('Admin', 'Super Admin', 'HR', 'HR Rep')
     AND NOT common.is_superuser_email(caller_email)
  THEN
    RAISE EXCEPTION 'Access denied - Admin or HR role required to read other users';
  END IF;

  SELECT u.raw_user_meta_data, u.email
  INTO target_metadata, target_email
  FROM auth.users u
  WHERE u.id = target_user_id;

  IF target_metadata IS NULL THEN
    RAISE EXCEPTION 'No user found with id %', target_user_id;
  END IF;

  RETURN target_metadata;
END;
$$;


--
-- Name: admin_get_users(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.admin_get_users() RETURNS TABLE(id uuid, email text, created_at timestamp with time zone, raw_user_meta_data jsonb, is_active boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
DECLARE
  caller_role  TEXT;
  caller_email TEXT;
BEGIN
  SELECT u.email, u.raw_user_meta_data->>'role'
  INTO caller_email, caller_role
  FROM auth.users u
  WHERE u.id = auth.uid();

  IF caller_role IS DISTINCT FROM 'Admin'
     AND NOT common.is_superuser_email(caller_email)
  THEN
    RAISE EXCEPTION 'Access denied - Admin role required';
  END IF;

  RETURN QUERY
  SELECT
    u.id,
    u.email::TEXT,
    u.created_at,
    u.raw_user_meta_data,
    CASE
      WHEN u.banned_until IS NOT NULL AND u.banned_until > NOW() THEN FALSE
      ELSE COALESCE(p.is_active, TRUE)
    END AS is_active
  FROM auth.users u
  LEFT JOIN common.profiles p ON p.id = u.id
  ORDER BY u.created_at DESC;
END;
$$;


--
-- Name: admin_set_user_active(uuid, boolean); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.admin_set_user_active(target_user_id uuid, active boolean) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
DECLARE
  caller_id    UUID;
  caller_role  TEXT;
  caller_email TEXT;
BEGIN
  caller_id := auth.uid();

  SELECT u.email, u.raw_user_meta_data->>'role'
  INTO caller_email, caller_role
  FROM auth.users u
  WHERE u.id = caller_id;

  -- Same gate as admin_update_user_role: Admins or superusers only.
  IF caller_role IS DISTINCT FROM 'Admin'
     AND NOT common.is_superuser_email(caller_email)
  THEN
    RAISE EXCEPTION 'Access denied – Admin role required';
  END IF;

  -- Don't let an admin lock themselves out.
  IF NOT active AND target_user_id = caller_id THEN
    RAISE EXCEPTION 'You cannot deactivate your own account';
  END IF;

  IF active THEN
    -- Reactivate: lift the login ban.
    UPDATE auth.users
    SET banned_until = NULL
    WHERE id = target_user_id;

    UPDATE common.profiles
    SET is_active = TRUE,
        deactivated_at = NULL,
        deactivated_by = NULL
    WHERE id = target_user_id;
  ELSE
    -- Deactivate: ban login far into the future and end live sessions now.
    UPDATE auth.users
    SET banned_until = NOW() + INTERVAL '100 years'
    WHERE id = target_user_id;

    DELETE FROM auth.sessions WHERE user_id = target_user_id;

    -- Profile row is preserved — only flagged — so report authorship stays.
    UPDATE common.profiles
    SET is_active = FALSE,
        deactivated_at = NOW(),
        deactivated_by = caller_id
    WHERE id = target_user_id;
  END IF;
END;
$$;


--
-- Name: admin_update_role(text, jsonb); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.admin_update_role(role_name text, role_config jsonb) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'neta_ops', 'business'
    AS $$
DECLARE
  v_prev_config JSONB;
  v_user_id UUID;
BEGIN
  SELECT auth.uid() INTO v_user_id;
  
  SELECT config INTO v_prev_config
  FROM common.custom_roles
  WHERE name = role_name;
  
  INSERT INTO common.custom_roles (name, config, created_by)
  VALUES (role_name, role_config, v_user_id)
  ON CONFLICT (name) 
  DO UPDATE SET 
    config = role_config,
    updated_at = NOW();
  
  RETURN TRUE;
END;
$$;


--
-- Name: admin_update_user_metadata(uuid, jsonb); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.admin_update_user_metadata(target_user_id uuid, new_metadata jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
DECLARE
  caller_id UUID;
  caller_role TEXT;
  caller_email TEXT;
  clean_metadata JSONB;
  updated_metadata JSONB;
  rows_updated INT;
BEGIN
  caller_id := auth.uid();

  SELECT u.email, u.raw_user_meta_data->>'role'
  INTO caller_email, caller_role
  FROM auth.users u
  WHERE u.id = caller_id;

  IF caller_id IS DISTINCT FROM target_user_id
     AND caller_role NOT IN ('Admin', 'Super Admin', 'HR', 'HR Rep')
     AND NOT common.is_superuser_email(caller_email)
  THEN
    RAISE EXCEPTION 'Access denied - Admin or HR role required to edit other users';
  END IF;

  clean_metadata := COALESCE(new_metadata, '{}'::jsonb) - 'role';

  UPDATE auth.users
  SET raw_user_meta_data = COALESCE(raw_user_meta_data, '{}'::jsonb) || clean_metadata
  WHERE id = target_user_id
  RETURNING raw_user_meta_data INTO updated_metadata;

  GET DIAGNOSTICS rows_updated = ROW_COUNT;

  IF rows_updated = 0 THEN
    RAISE EXCEPTION 'No user found with id %', target_user_id;
  END IF;

  RETURN updated_metadata;
END;
$$;


--
-- Name: admin_update_user_role(uuid, text); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.admin_update_user_role(user_id uuid, new_role text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
DECLARE
  caller_id UUID;
  caller_email TEXT;
  caller_role TEXT;
  old_role TEXT;
BEGIN
  caller_id := auth.uid();

  SELECT u.email, u.raw_user_meta_data->>'role'
  INTO caller_email, caller_role
  FROM auth.users u
  WHERE u.id = caller_id;

  IF caller_role IS DISTINCT FROM 'Admin'
     AND NOT common.is_superuser_email(caller_email)
  THEN
    RAISE EXCEPTION 'Access denied – Admin role required';
  END IF;

  SELECT u.raw_user_meta_data->>'role'
  INTO old_role
  FROM auth.users u
  WHERE u.id = user_id;

  UPDATE auth.users
  SET raw_user_meta_data = raw_user_meta_data || jsonb_build_object('role', new_role)
  WHERE id = user_id;

  INSERT INTO common.role_change_logs (user_id, subject_id, old_role, new_role, reason, component)
  VALUES (
    user_id::text,
    caller_id::text,
    old_role,
    new_role,
    'Role updated via Admin Dashboard',
    'AdminUserManagement'
  );
END;
$$;


--
-- Name: assign_feature_request_priority(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.assign_feature_request_priority() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- If no priority_order is specified, assign the next highest number
    IF NEW.priority_order = 0 THEN
        SELECT COALESCE(MAX(priority_order), 0) + 1 
        INTO NEW.priority_order 
        FROM common.feature_requests;
    END IF;
    
    -- Set updated_at timestamp
    NEW.updated_at = NOW();
    
    RETURN NEW;
END;
$$;


--
-- Name: award_ppe_testing_xp(uuid, text, uuid, text, uuid); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.award_ppe_testing_xp(p_user_id uuid, p_task_type text, p_report_id uuid, p_report_type text, p_job_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
declare xp_amount integer; task_description text; existing_entry_count integer;
begin
  select count(*) into existing_entry_count
  from common.xp_entries
  where user_id = p_user_id and report_id = p_report_id and report_type = p_report_type;
  if existing_entry_count > 0 then return false; end if;

  case p_task_type
    when 'blanket' then xp_amount := 1; task_description := 'Insulated Blanket Testing';
    when 'glove' then xp_amount := 1; task_description := 'Insulated Glove Testing';
    when 'sleeve' then xp_amount := 1; task_description := 'Insulated Sleeve Testing';
    when 'line_hose' then xp_amount := 1; task_description := 'Line Hose Testing';
    when 'grounding_cable' then xp_amount := 3; task_description := 'Grounding Cable Testing';
    when 'hotstick' then xp_amount := 5; task_description := 'Hotstick Testing';
    when 'bucket_truck' then xp_amount := 15; task_description := 'Bucket Truck Testing';
    when 'digger_derrick' then xp_amount := 15; task_description := 'Digger Derrick Testing';
    else return false;
  end case;

  insert into common.xp_entries (user_id, xp_amount, task_type, task_description, report_id, report_type, job_id, created_by)
  values (p_user_id, xp_amount, p_task_type, task_description, p_report_id, p_report_type, p_job_id, p_user_id);

  insert into common.user_xp (user_id, total_xp)
  values (p_user_id, xp_amount)
  on conflict (user_id) do update
    set total_xp = common.user_xp.total_xp + excluded.total_xp,
        updated_at = now();

  update common.user_xp set (tier, level) = (
    select tier, level from common.calculate_tier_and_level(total_xp) limit 1
  ) where user_id = p_user_id;

  return true;
end $$;


--
-- Name: calculate_tier_and_level(integer); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.calculate_tier_and_level(total_xp integer) RETURNS TABLE(tier integer, level integer, progress numeric)
    LANGUAGE plpgsql
    AS $$
declare cumulative_xp integer := 0; level_xp integer; base_xp constant integer := 750; multiplier constant numeric := 1.05;
begin
  for tier in 1..5 loop
    for level in 1..10 loop
      level_xp := floor(base_xp * pow(multiplier, (tier - 1) * 10 + level - 1));
      cumulative_xp := cumulative_xp + level_xp;
      if total_xp < cumulative_xp then
        progress := least(((total_xp - (cumulative_xp - level_xp))::numeric / level_xp::numeric) * 100, 100);
        return next; return;
      end if;
    end loop;
  end loop;
  tier := 5; level := 10; progress := 100; return next; return;
end $$;


