--
-- Name: customer_deliverables(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.customer_deliverables() RETURNS TABLE(id uuid, job_id uuid, name text, description text, status text, delivered_at timestamp with time zone, created_at timestamp with time zone, report_asset_ids uuid[])
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'common', 'neta_ops', 'public'
    AS $$
  SELECT
    d.id,
    d.job_id,
    d.name,
    d.description,
    d.status,
    d.delivered_at,
    d.created_at,
    COALESCE(gd.selected_report_ids, '{}')::uuid[]
  FROM neta_ops.deliverables d
  JOIN neta_ops.jobs j ON j.id = d.job_id
  LEFT JOIN neta_ops.generated_documents gd ON gd.id = d.cover_letter_id
  WHERE j.customer_id = common.current_customer_id()
    AND j.deleted_at IS NULL
    AND lower(coalesce(d.status, '')) = 'delivered'
  ORDER BY coalesce(d.delivered_at, d.created_at) DESC;
$$;


