--

CREATE FUNCTION common.customer_report_assets() RETURNS TABLE(asset_id uuid, asset_name text, file_url text, substation text, status text, submitted_at timestamp with time zone, approved_at timestamp with time zone, sent_at timestamp with time zone, created_at timestamp with time zone, published_pdf_path text, job_id uuid, job_number text, job_title text, flag_count bigint)
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'common', 'neta_ops', 'public'
    AS $$
  SELECT
    a.id,
    a.name,
    a.file_url,
    a.substation,
    a.status,
    a.submitted_at,
    a.approved_at,
    a.sent_at,
    a.created_at,
    a.published_pdf_path,
    j.id,
    j.job_number,
    j.title,
    (SELECT count(*) FROM common.report_flags rf
      WHERE rf.asset_id = a.id
        AND rf.flagged_by = auth.uid()
        AND rf.status = 'open')
  FROM neta_ops.jobs j
  JOIN neta_ops.job_assets ja ON ja.job_id = j.id
  JOIN neta_ops.assets a ON a.id = ja.asset_id
  WHERE j.customer_id = common.current_customer_id()
    AND j.deleted_at IS NULL
    AND lower(coalesce(a.status, '')) IN ('approved', 'sent')
  ORDER BY coalesce(a.sent_at, a.approved_at, a.created_at) DESC;
$$;


