--
-- Name: customer_revoke_report_flag(uuid); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.customer_revoke_report_flag(p_flag_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
BEGIN
  UPDATE common.report_flags
  SET status = 'resolved',
      resolved_by = auth.uid(),
      resolved_at = NOW(),
      resolution_comment = 'Revoked by customer'
  WHERE id = p_flag_id
    AND flagged_by = auth.uid()
    AND status = 'open';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Flag not found or not yours to revoke.';
  END IF;
END;
$$;


--
-- Name: customer_update_branding(text, text); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.customer_update_branding(p_logo_url text, p_brand_primary text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $_$
DECLARE
  v_id uuid := common.current_customer_id();
  v_logo_url text := nullif(btrim(p_logo_url), '');
  v_brand_primary text := upper(nullif(btrim(p_brand_primary), ''));
BEGIN
  IF v_id IS NULL THEN
    RAISE EXCEPTION 'Not a customer account';
  END IF;

  IF v_brand_primary IS NOT NULL AND v_brand_primary !~* '^#[0-9a-f]{6}$' THEN
    RAISE EXCEPTION 'Primary brand color must be a hex color like #FF6400';
  END IF;

  UPDATE common.customers
     SET logo_url = v_logo_url,
         brand_primary = v_brand_primary
   WHERE id = v_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Company not found';
  END IF;
END;
$_$;


