-- Name: customer_update_company(text, text, text, text); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.customer_update_company(p_company_name text, p_address text, p_phone text, p_email text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
DECLARE
  v_id uuid := common.current_customer_id();
BEGIN
  IF v_id IS NULL THEN
    RAISE EXCEPTION 'Not a customer account';
  END IF;

  UPDATE common.customers
     SET company_name = p_company_name,
         address      = p_address,
         phone        = p_phone,
         email        = p_email
   WHERE id = v_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Company not found';
  END IF;
END;
$$;


--
-- Name: customer_upsert_contact(uuid, text, text, text, text, text, boolean); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.customer_upsert_contact(p_id uuid, p_first_name text, p_last_name text, p_email text, p_phone text, p_position text, p_is_primary boolean) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
DECLARE
  v_id uuid := common.current_customer_id();
BEGIN
  IF v_id IS NULL THEN
    RAISE EXCEPTION 'Not a customer account';
  END IF;

  IF p_id IS NULL THEN
    INSERT INTO common.contacts
      (customer_id, first_name, last_name, email, phone, position, is_primary)
    VALUES
      (v_id, p_first_name, p_last_name, p_email, p_phone, p_position, COALESCE(p_is_primary, false));
  ELSE
    UPDATE common.contacts
       SET first_name = p_first_name,
           last_name  = p_last_name,
           email      = p_email,
           phone      = p_phone,
           position   = p_position,
           is_primary = COALESCE(p_is_primary, is_primary)
     WHERE id = p_id
       AND customer_id = v_id;            -- can only touch own company's contacts

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Contact not found for this company';
    END IF;
  END IF;
END;
$$;


