--
-- Name: delete_old_chat_messages(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.delete_old_chat_messages() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    deleted_count INTEGER;
    retention_start TIMESTAMPTZ;
BEGIN
    -- Get the retention start timestamp
    SELECT (value->>'timestamp')::TIMESTAMPTZ 
    INTO retention_start 
    FROM common.system_config 
    WHERE key = 'message_retention_start';

    -- Delete messages older than 24 hours, but only those created after retention_start
    WITH deleted AS (
        DELETE FROM common.chat_messages
        WHERE created_at < NOW() - INTERVAL '24 hours'
        AND created_at >= retention_start
        RETURNING *
    )
    SELECT COUNT(*) INTO deleted_count FROM deleted;
    
    -- Log the deletion count
    INSERT INTO common.system_logs (
        event_type,
        description,
        metadata
    ) VALUES (
        'message_cleanup',
        'Deleted old chat messages',
        jsonb_build_object(
            'deleted_count', deleted_count,
            'deletion_time', NOW(),
            'retention_start', retention_start
        )
    );
END;
$$;


--
-- Name: FUNCTION delete_old_chat_messages(); Type: COMMENT; Schema: common; Owner: -
--

COMMENT ON FUNCTION common.delete_old_chat_messages() IS 'This function should be run periodically (e.g., hourly) to delete chat messages older than 24 hours. Since pg_cron is not available, set up an external scheduler or run manually.';


--
-- Name: enforce_issue_report_permissions(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.enforce_issue_report_permissions() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  jwt jsonb;
  email text;
  user_id uuid;
BEGIN
  BEGIN
    jwt := auth.jwt();
  EXCEPTION WHEN OTHERS THEN
    jwt := '{}'::jsonb;
  END;
  email := coalesce(jwt ->> 'email', '');
  user_id := (jwt ->> 'sub')::uuid;

  IF new.status IS DISTINCT FROM old.status AND new.status IN ('resolved', 'closed') THEN
    IF NOT common.is_superuser_email(email) THEN
      RAISE EXCEPTION 'Only authorized administrators can mark issues as complete';
    END IF;
    IF new.resolved_at IS NULL THEN
      new.resolved_at := now();
    END IF;
  END IF;

  IF new.priority IS DISTINCT FROM old.priority THEN
    IF old.reporter_id IS NULL OR old.reporter_id <> user_id THEN
      IF NOT common.is_superuser_email(email) THEN
        RAISE EXCEPTION 'Only the original reporter or an administrator can change priority';
      END IF;
    END IF;
  END IF;

  RETURN new;
END;
$$;


--
-- Name: find_available_technicians(uuid, date, time without time zone, time without time zone, text); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.find_available_technicians(job_id uuid, assignment_date date, start_time time without time zone, end_time time without time zone, portal text) RETURNS TABLE(user_id uuid, full_name text, email text, division text, skill_match_score integer, availability_conflicts text[])
    LANGUAGE sql
    AS $$
  with base as (
    select a.user_id, u.email, (u.raw_user_meta_data->>'name') as full_name, a.division
    from common.technician_availability a
    join auth.users u on u.id = a.user_id
    where a.portal_type = portal
      and a.day_of_week = extract(dow from assignment_date)
      and a.start_time <= start_time and a.end_time >= end_time
  )
  select b.user_id, b.full_name, b.email, b.division,
         100 as skill_match_score,
         array[]::text[] as availability_conflicts
  from base b;
$$;


--
-- Name: flag_report(uuid, text); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.flag_report(p_asset_id uuid, p_reason text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'neta_ops', 'public'
    AS $$
DECLARE
  v_customer_id uuid;
  v_flag_id uuid;
BEGIN
  IF coalesce(btrim(p_reason), '') = '' THEN
    RAISE EXCEPTION 'A reason is required to flag a report.';
  END IF;

  -- Match the visibility logic of common.customer_report_assets() so that
  -- every report the portal lists can actually be flagged.
  IF NOT EXISTS (
    SELECT 1
    FROM neta_ops.jobs j
    JOIN neta_ops.job_assets ja ON ja.job_id = j.id
    JOIN neta_ops.assets a ON a.id = ja.asset_id
    WHERE a.id = p_asset_id
      AND j.customer_id = common.current_customer_id()
      AND j.deleted_at IS NULL
      AND lower(coalesce(a.status, '')) IN ('approved', 'sent')
  ) THEN
    RAISE EXCEPTION 'Not authorized to flag this report.';
  END IF;

  v_customer_id := common.current_customer_id();

  INSERT INTO common.report_flags (asset_id, customer_id, flagged_by, reason)
  VALUES (p_asset_id, v_customer_id, auth.uid(), btrim(p_reason))
  RETURNING id INTO v_flag_id;

  RETURN v_flag_id;
END;
$$;


--
-- Name: generate_requisition_number(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.generate_requisition_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
    year_prefix VARCHAR(4);
    sequence_num INTEGER;
    new_number VARCHAR(50);
BEGIN
    -- Only generate if not already set
    IF NEW.requisition_number IS NULL THEN
        year_prefix := TO_CHAR(NOW(), 'YYYY');
        
        -- Get the next sequence number for this year
        SELECT COALESCE(MAX(CAST(SUBSTRING(requisition_number FROM '[0-9]+$') AS INTEGER)), 0) + 1
        INTO sequence_num
        FROM common.job_requisitions
        WHERE requisition_number LIKE 'REQ-' || year_prefix || '-%';
        
        -- Format: REQ-YYYY-XXXXX
        new_number := 'REQ-' || year_prefix || '-' || LPAD(sequence_num::TEXT, 5, '0');
        NEW.requisition_number := new_number;
    END IF;
    
    RETURN NEW;
END;
$_$;


