--
-- Name: handle_issue_pause_resume(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.handle_issue_pause_resume() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- When status changes TO 'paused', record the pause timestamp
  IF NEW.status = 'paused' AND (OLD.status IS NULL OR OLD.status != 'paused') THEN
    NEW.paused_at := NOW();
  END IF;

  -- When status changes FROM 'paused' to something else, accumulate the pause time
  IF OLD.status = 'paused' AND NEW.status != 'paused' AND OLD.paused_at IS NOT NULL THEN
    -- Calculate pause duration and add to total
    NEW.total_paused_ms := COALESCE(OLD.total_paused_ms, 0) + 
                           EXTRACT(EPOCH FROM (NOW() - OLD.paused_at)) * 1000;
    -- Clear paused_at since we're no longer paused
    NEW.paused_at := NULL;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: handle_job_requisition_status_change(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.handle_job_requisition_status_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Set timestamps based on status changes
    IF NEW.status = 'pending_approval' AND OLD.status != 'pending_approval' THEN
        NEW.submitted_for_approval_at = NOW();
    END IF;
    
    IF NEW.status = 'approved' AND OLD.status != 'approved' THEN
        NEW.approved_at = NOW();
        NEW.approved_by = COALESCE(NEW.approved_by, auth.uid());
    END IF;
    
    IF NEW.status = 'posted' AND OLD.status != 'posted' THEN
        NEW.posted_at = NOW();
        NEW.posted_by = COALESCE(NEW.posted_by, auth.uid());
    END IF;
    
    IF NEW.status = 'closed' AND OLD.status != 'closed' THEN
        NEW.closed_at = NOW();
        NEW.closed_by = COALESCE(NEW.closed_by, auth.uid());
    END IF;
    
    -- Increment version on status change or significant update
    IF NEW.status != OLD.status OR 
       NEW.title != OLD.title OR 
       NEW.department != OLD.department OR
       NEW.salary_range_min != OLD.salary_range_min OR
       NEW.salary_range_max != OLD.salary_range_max THEN
        NEW.version = OLD.version + 1;
    END IF;
    
    RETURN NEW;
END;
$$;


