-- Name: is_admin_or_scheduler(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.is_admin_or_scheduler() RETURNS boolean
    LANGUAGE sql STABLE
    AS $$
  select
    coalesce(auth.jwt()->'user_metadata'->>'role','') = 'Admin'
    or coalesce(auth.jwt()->'user_metadata'->>'role','') ilike '%Scheduler%';
$$;


--
-- Name: is_employee_user(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.is_employee_user() RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
  SELECT
    auth.role() = 'authenticated'
    AND (
      lower(coalesce(auth.jwt() ->> 'email', '')) LIKE '%@ampqes.com'
      OR lower(coalesce(auth.jwt() -> 'app_metadata' ->> 'account_type', '')) = 'employee'
      OR lower(coalesce(auth.jwt() -> 'user_metadata' ->> 'account_type', '')) = 'employee'
      OR lower(coalesce(auth.jwt() -> 'app_metadata' ->> 'user_type', '')) = 'employee'
      OR lower(coalesce(auth.jwt() -> 'user_metadata' ->> 'user_type', '')) = 'employee'
      OR lower(coalesce(auth.jwt() -> 'app_metadata' ->> 'role', '')) IN (
        'admin',
        'manager',
        'supervisor',
        'neta technician',
        'technician',
        'sales',
        'estimator',
        'engineering',
        'office admin',
        'hr_manager',
        'hr_personnel'
      )
      OR lower(coalesce(auth.jwt() -> 'user_metadata' ->> 'role', '')) IN (
        'admin',
        'manager',
        'supervisor',
        'neta technician',
        'technician',
        'sales',
        'estimator',
        'engineering',
        'office admin',
        'hr_manager',
        'hr_personnel'
      )
    );
$$;


