--
-- Name: log_encryption_event(text, text, text, jsonb); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.log_encryption_event(p_event_type text, p_table_name text DEFAULT NULL::text, p_record_id text DEFAULT NULL::text, p_metadata jsonb DEFAULT NULL::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'neta_ops', 'business'
    AS $$
DECLARE
  v_user_id UUID;
  v_log_id UUID;
BEGIN
  -- Get the current user ID
  SELECT auth.uid() INTO v_user_id;
  
  -- Insert the log entry
  INSERT INTO common.encryption_audit_logs
    (event_type, table_name, record_id, user_id, metadata)
  VALUES
    (p_event_type, p_table_name, p_record_id, v_user_id, p_metadata)
  RETURNING id INTO v_log_id;
  
  RETURN v_log_id;
END;
$$;


