--
-- Name: log_permission_access(text, text, text, text, text, text, boolean, text, jsonb); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.log_permission_access(p_user_id text, p_role text, p_resource text, p_action text, p_scope text, p_target_id text DEFAULT NULL::text, p_granted boolean DEFAULT false, p_reason text DEFAULT NULL::text, p_details jsonb DEFAULT NULL::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'neta_ops', 'business'
    AS $$
DECLARE
  v_ip TEXT;
  v_user_agent TEXT;
  v_log_id UUID;
BEGIN
  -- Get IP and user agent from request headers if available
  v_ip := coalesce(current_setting('request.headers', true)::json->>'x-forwarded-for', 'unknown');
  v_user_agent := coalesce(current_setting('request.headers', true)::json->>'user-agent', 'unknown');
  
  -- Insert the log entry
  INSERT INTO common.permission_access_logs
    (user_id, role, resource, action, scope, target_id, granted, reason, details, ip_address, user_agent)
  VALUES
    (p_user_id, p_role, p_resource, p_action, p_scope, p_target_id, p_granted, p_reason, p_details, v_ip, v_user_agent)
  RETURNING id INTO v_log_id;
  
  RETURN v_log_id;
END;
$$;


