-- Name: reorder_feature_requests(uuid[], integer[]); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.reorder_feature_requests(request_ids uuid[], new_orders integer[]) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    i INTEGER;
BEGIN
    FOR i IN 1..array_length(request_ids, 1) LOOP
        UPDATE common.feature_requests 
        SET priority_order = new_orders[i]
        WHERE id = request_ids[i];
    END LOOP;
    
    RETURN TRUE;
END;
$$;


