-- Name: resolve_report_flag(uuid, text); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.resolve_report_flag(p_flag_id uuid, p_comment text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common', 'public'
    AS $$
BEGIN
  IF NOT common.is_employee_user() THEN
    RAISE EXCEPTION 'Not authorized to resolve report flags.';
  END IF;

  UPDATE common.report_flags
  SET status = 'resolved',
      resolved_by = auth.uid(),
      resolved_at = NOW(),
      resolution_comment = p_comment
  WHERE id = p_flag_id;
END;
$$;


--
-- Name: seed_digest_prefs_for_email(text, jsonb); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.seed_digest_prefs_for_email(p_email text, p_automated jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'common'
    AS $$
DECLARE
  v_user_id uuid;
  v_existing jsonb;
  v_merged jsonb;
BEGIN
  SELECT id INTO v_user_id
  FROM common.profiles
  WHERE lower(trim(email)) = lower(trim(p_email))
  LIMIT 1;

  IF v_user_id IS NULL THEN
    RAISE NOTICE 'No profile for email %', p_email;
    RETURN;
  END IF;

  SELECT notification_preferences INTO v_existing
  FROM common.user_preferences
  WHERE user_id = v_user_id;

  v_merged := coalesce(v_existing, '{}'::jsonb)
    || jsonb_build_object(
      'automatedEmails',
      coalesce(v_existing->'automatedEmails', '{}'::jsonb) || p_automated
    );

  INSERT INTO common.user_preferences (user_id, notification_preferences, updated_at)
  VALUES (v_user_id, v_merged, now())
  ON CONFLICT (user_id) DO UPDATE
  SET notification_preferences = EXCLUDED.notification_preferences,
      updated_at = now();
END;
$$;


