--
-- Name: test_minimal_visibility(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.test_minimal_visibility() RETURNS TABLE(room_id uuid, room_name text, room_role_access text, user_role text, is_visible boolean, condition_met text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_user_role TEXT;
BEGIN
  v_user_role := LOWER(COALESCE((auth.jwt() ->> 'role')::text, 'null_role'));
  
  RETURN QUERY
  SELECT 
    r.id,
    r.name,
    r.role_access,
    v_user_role,
    (
      r.role_access = 'All' OR
      LOWER(r.role_access) = v_user_role OR
      (v_user_role LIKE '%admin%' AND r.name = 'Admin')
    ) as is_visible,
    CASE
      WHEN r.role_access = 'All' THEN 'role_access=All'
      WHEN LOWER(r.role_access) = v_user_role THEN 'LOWER(role_access)=user_role'
      WHEN (v_user_role LIKE '%admin%' AND r.name = 'Admin') THEN 'user_role LIKE %admin% AND name=Admin'
      ELSE 'None'
    END AS condition_met
  FROM common.chat_rooms r
  ORDER BY r.name;
END;
$$;


--
-- Name: test_room_visibility(); Type: FUNCTION; Schema: common; Owner: -
--

CREATE FUNCTION common.test_room_visibility() RETURNS TABLE(room_id uuid, room_name text, room_role_access text, user_role text, is_visible boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_user_role TEXT;
BEGIN
  v_user_role := auth.jwt() ->> 'role';
  
  RETURN QUERY
  SELECT 
    r.id,
    r.name,
    r.role_access,
    v_user_role,
    (r.role_access = 'All') OR (LOWER(r.role_access) = LOWER(v_user_role)) as is_visible
  FROM common.chat_rooms r
  ORDER BY r.name;
END;
$$;


