--
-- Name: generate_requisition_number(); Type: FUNCTION; Schema: hr; Owner: -
--

CREATE FUNCTION hr.generate_requisition_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
    year_prefix VARCHAR(4);
    sequence_num INTEGER;
    new_number VARCHAR(50);
BEGIN
    -- Only generate if not already set
    IF NEW.requisition_number IS NULL THEN
        year_prefix := TO_CHAR(NOW(), 'YYYY');
        
        -- Get the next sequence number for this year
        SELECT COALESCE(MAX(CAST(SUBSTRING(requisition_number FROM '[0-9]+$') AS INTEGER)), 0) + 1
        INTO sequence_num
        FROM hr.job_requisitions
        WHERE requisition_number LIKE 'REQ-' || year_prefix || '-%';
        
        -- Format: REQ-YYYY-XXXXX
        new_number := 'REQ-' || year_prefix || '-' || LPAD(sequence_num::TEXT, 5, '0');
        NEW.requisition_number := new_number;
    END IF;
    
    RETURN NEW;
END;
$_$;


--
-- Name: handle_job_requisition_status_change(); Type: FUNCTION; Schema: hr; Owner: -
--

CREATE FUNCTION hr.handle_job_requisition_status_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Set timestamps based on status changes
    IF NEW.status = 'pending_approval' AND OLD.status != 'pending_approval' THEN
        NEW.submitted_for_approval_at = NOW();
    END IF;
    
    IF NEW.status = 'approved' AND OLD.status != 'approved' THEN
        NEW.approved_at = NOW();
        NEW.approved_by = COALESCE(NEW.approved_by, auth.uid());
    END IF;
    
    IF NEW.status = 'posted' AND OLD.status != 'posted' THEN
        NEW.posted_at = NOW();
        NEW.posted_by = COALESCE(NEW.posted_by, auth.uid());
    END IF;
    
    IF NEW.status = 'closed' AND OLD.status != 'closed' THEN
        NEW.closed_at = NOW();
        NEW.closed_by = COALESCE(NEW.closed_by, auth.uid());
    END IF;
    
    -- Increment version on status change or significant update
    IF NEW.status != OLD.status OR 
       NEW.title != OLD.title OR 
       NEW.department != OLD.department OR
       NEW.salary_range_min != OLD.salary_range_min OR
       NEW.salary_range_max != OLD.salary_range_max THEN
        NEW.version = OLD.version + 1;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: add_user_role(uuid, text); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.add_user_role(p_user_id uuid, p_role text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_role_id UUID;
BEGIN
  -- Insert role if it doesn't exist yet
  INSERT INTO neta_ops.user_roles (user_id, role)
  VALUES (p_user_id, p_role)
  ON CONFLICT (user_id, role) DO NOTHING
  RETURNING id INTO v_role_id;
  
  -- If we didn't insert (already existed), get the existing ID
  IF v_role_id IS NULL THEN
    SELECT id INTO v_role_id
    FROM neta_ops.user_roles
    WHERE user_id = p_user_id AND role = p_role;
  END IF;
  
  RETURN v_role_id;
END;
$$;


