  WHERE asset_id = OLD.id;
  
  RETURN OLD;
END;
$$;


--
-- Name: create_job_revenue_table(); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.create_job_revenue_table() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- Check if the table exists
    IF NOT EXISTS (SELECT FROM pg_tables WHERE schemaname = 'neta_ops' AND tablename = 'job_revenue') THEN
        -- Create the table
        CREATE TABLE neta_ops.job_revenue (
            id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
            job_id UUID NOT NULL REFERENCES neta_ops.jobs(id) ON DELETE CASCADE,
            description TEXT NOT NULL,
            amount DECIMAL(12, 2) NOT NULL,
            revenue_type TEXT NOT NULL CHECK (revenue_type IN ('invoice', 'payment', 'other')),
            date DATE NOT NULL,
            status TEXT NOT NULL CHECK (status IN ('pending', 'approved', 'paid')),
            notes TEXT,
            created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
            updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
        );

        -- Create update timestamp trigger
        CREATE TRIGGER update_job_revenue_timestamp
        BEFORE UPDATE ON neta_ops.job_revenue
        FOR EACH ROW
        EXECUTE FUNCTION neta_ops.update_timestamp();

        -- Add indexes
        CREATE INDEX idx_job_revenue_job_id ON neta_ops.job_revenue(job_id);
        CREATE INDEX idx_job_revenue_revenue_type ON neta_ops.job_revenue(revenue_type);
        CREATE INDEX idx_job_revenue_date ON neta_ops.job_revenue(date);
        CREATE INDEX idx_job_revenue_status ON neta_ops.job_revenue(status);

        -- Enable RLS
        ALTER TABLE neta_ops.job_revenue ENABLE ROW LEVEL SECURITY;

        -- Create policies
        CREATE POLICY job_revenue_select_policy ON neta_ops.job_revenue
            FOR SELECT
            USING (true);

        CREATE POLICY job_revenue_insert_policy ON neta_ops.job_revenue
            FOR INSERT
            WITH CHECK (auth.uid() IS NOT NULL);

        CREATE POLICY job_revenue_update_policy ON neta_ops.job_revenue
            FOR UPDATE
            USING (auth.uid() IS NOT NULL);

        CREATE POLICY job_revenue_delete_policy ON neta_ops.job_revenue
            FOR DELETE
            USING (auth.uid() IS NOT NULL);
            
        RAISE NOTICE 'Created job_revenue table';
    ELSE
        RAISE NOTICE 'job_revenue table already exists';
    END IF;
END;
$$;


--
-- Name: create_report_notifications(); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.create_report_notifications() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  relevant_users UUID[];
  user_id UUID;
BEGIN
  -- Only create notifications for specific statuses
  IF NEW.status NOT IN ('ready_for_review', 'issue', 'approved') THEN
    RETURN NEW;
  END IF;

  -- Get all users who should be notified for this asset
  -- Get reviewers for this asset
  SELECT ARRAY_AGG(DISTINCT ar.reviewer_id) INTO relevant_users
  FROM neta_ops.asset_reviewers ar
  WHERE ar.asset_id = NEW.id;

  -- If no specific reviewers found, we'll skip creating notifications
  -- The application layer can handle admin notifications separately if needed
  IF relevant_users IS NULL OR array_length(relevant_users, 1) IS NULL THEN
    -- For now, don't create notifications if no reviewers assigned
    -- This prevents the function from failing when there's no users table
    RETURN NEW;
  END IF;

  -- Create notification entries for each relevant user
  IF relevant_users IS NOT NULL THEN
    FOREACH user_id IN ARRAY relevant_users
    LOOP
      INSERT INTO neta_ops.report_notifications (user_id, asset_id, status, seen)
      VALUES (user_id, NEW.id, NEW.status, FALSE)
      ON CONFLICT (user_id, asset_id, status) 
      DO UPDATE SET 
        seen = FALSE,
        seen_at = NULL,
        updated_at = NOW();
    END LOOP;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: find_available_technicians(uuid, date, time without time zone, time without time zone, text); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.find_available_technicians(job_id uuid, assignment_date date, start_time time without time zone, end_time time without time zone, portal text) RETURNS TABLE(user_id uuid, full_name text, email text, division text, skill_match_score integer, availability_conflicts text[])
    LANGUAGE sql
    AS $$
  with base as (
    select a.user_id, u.email, (u.raw_user_meta_data->>'name') as full_name, a.division
    from common.technician_availability a
    join auth.users u on u.id = a.user_id
    where a.portal_type = portal
      and a.day_of_week = extract(dow from assignment_date)
      and a.start_time <= start_time and a.end_time >= end_time
  )
  select b.user_id, b.full_name, b.email, b.division,
         100 as skill_match_score,
         array[]::text[] as availability_conflicts
  from base b;
$$;


--
-- Name: find_user_by_name(text); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.find_user_by_name(search_name text) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  user_id UUID;
  first_name TEXT;
  last_name TEXT;
  email_pattern TEXT;
BEGIN
  -- Try to find by exact name match in user_metadata
  SELECT id INTO user_id
  FROM auth.users
  WHERE raw_user_meta_data->>'name' ILIKE '%' || search_name || '%'
  LIMIT 1;
  
  -- If not found, try to derive from email (assuming format: firstname.lastname@ampqes.com)
  IF user_id IS NULL THEN
    -- Extract first and last name from search_name (assuming "First Last" format)
    first_name := split_part(search_name, ' ', 1);
    last_name := split_part(search_name, ' ', 2);
    
    IF last_name IS NOT NULL AND last_name != '' THEN
      email_pattern := LOWER(first_name) || '.' || LOWER(last_name) || '@ampqes.com';
      
      SELECT id INTO user_id
      FROM auth.users
      WHERE email = email_pattern
      LIMIT 1;
    END IF;
  END IF;
  
  RETURN user_id;
END;
$$;


--
-- Name: fn_attach_backup(text); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.fn_attach_backup(p_table text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'neta_ops', 'public'
    AS $$
begin
  if p_table <> 'backup_reports' then
    execute format('drop trigger if exists trg_backup_%I on neta_ops.%I;', p_table, p_table);
    execute format('create trigger trg_backup_%I after insert or update on neta_ops.%I for each row execute function neta_ops.fn_backup_row();', p_table, p_table);
  end if;
end; $$;


--
-- Name: fn_attach_report_snapshot(text, text); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.fn_attach_report_snapshot(p_schema text, p_table text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
declare
  v_trg_ins_long text;
  v_trg_upd_long text;
  v_trg_ins_short text;
  v_trg_upd_short text;
  v_trg_ins text;
  v_trg_upd text;
begin
  -- Skip attaching to the backup table itself
  if p_schema = 'neta_ops' and p_table = 'backup_reports' then
    return;
  end if;

  -- Build trigger names; ensure <= 63 bytes by hashing when necessary
  v_trg_ins_long := format('trg_snapshot_%s_ins', p_table);
  v_trg_upd_long := format('trg_snapshot_%s_upd', p_table);
  v_trg_ins_short := format('trg_snapshot_%s_ins', substring(md5(p_table) from 1 for 16));
  v_trg_upd_short := format('trg_snapshot_%s_upd', substring(md5(p_table) from 1 for 16));

  if length(v_trg_ins_long) > 63 then
    v_trg_ins := v_trg_ins_short;
  else
    v_trg_ins := v_trg_ins_long;
  end if;

  if length(v_trg_upd_long) > 63 then
    v_trg_upd := v_trg_upd_short;
  else
    v_trg_upd := v_trg_upd_long;
  end if;

  -- Drop both old-style (long) and new-style (hashed) names if they exist
  execute format('drop trigger if exists %I on %I.%I;', v_trg_ins_long, p_schema, p_table);
  execute format('drop trigger if exists %I on %I.%I;', v_trg_upd_long, p_schema, p_table);
  execute format('drop trigger if exists %I on %I.%I;', v_trg_ins_short, p_schema, p_table);
  execute format('drop trigger if exists %I on %I.%I;', v_trg_upd_short, p_schema, p_table);

  -- After INSERT: always snapshot first version
  execute format(
    'create trigger %1$I after insert on %2$I.%3$I for each row execute function neta_ops.fn_snapshot_report_json();',
    v_trg_ins, p_schema, p_table
  );

  -- After UPDATE on any column: function internally compares payloads to avoid noise
  execute format(
    'create trigger %1$I after update on %2$I.%3$I for each row execute function neta_ops.fn_snapshot_report_json();',
    v_trg_upd, p_schema, p_table
  );
end; $_$;


--
-- Name: fn_backup_on_create_table(); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.fn_backup_on_create_table() RETURNS event_trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'neta_ops', 'public'
    AS $$
declare cmd record;
begin
  for cmd in select * from pg_event_trigger_ddl_commands() loop
    if cmd.object_type = 'table' and cmd.schema_name = 'neta_ops' and cmd.object_name <> 'backup_reports' then
      perform neta_ops.fn_attach_backup(cmd.object_name);
    end if;
  end loop;
end; $$;


--
-- Name: fn_backup_row(); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.fn_backup_row() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'neta_ops', 'public'
    AS $_$
declare
  v_pk text := null;
begin
  -- Try to capture a primary key value named "id" if it exists
  begin
    if tg_op in ('INSERT','UPDATE') then
      execute 'select ($1).id::text' into v_pk using new;
    end if;
  exception when others then v_pk := null; end;

  insert into neta_ops.backup_reports (source_schema, source_table, row_pk, action, data)
  values (tg_table_schema, tg_table_name, v_pk, lower(tg_op), to_jsonb(new));

  return new;
end; $_$;


--
-- Name: fn_on_create_table_snapshot(); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.fn_on_create_table_snapshot() RETURNS event_trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare cmd record;
begin
  for cmd in select * from pg_event_trigger_ddl_commands() loop
    if cmd.object_type = 'table' and cmd.schema_name = 'neta_ops' then
      perform neta_ops.fn_attach_report_snapshot(cmd.schema_name, cmd.object_name);
    end if;
  end loop;
end; $$;


--
-- Name: fn_prevent_modify_backup(); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.fn_prevent_modify_backup() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  raise exception 'neta_ops.backup_reports is immutable; % not allowed', tg_op;
end; $$;


--
-- Name: fn_snapshot_report_json(); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.fn_snapshot_report_json() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_payload_new jsonb;
  v_payload_old jsonb;
  v_source_id uuid;
  v_row_pk text;
  v_job_id uuid;
  v_report_type text;
  v_title text;
  v_next_version int;
begin
  -- Build full-row JSON payloads and scrub non-report fields
  -- Remove 'status' so backups don't store workflow state
  v_payload_new := to_jsonb(NEW) - 'status';
  v_payload_old := to_jsonb(OLD) - 'status';

  -- Only snapshot on INSERT, or on UPDATE where JSON payload changed
  if tg_op = 'UPDATE' and not (v_payload_new is distinct from v_payload_old) then
    return NEW;
  end if;

  -- Common metadata best-effort (all pulled from row JSON to avoid tight coupling)
  begin v_source_id := (to_jsonb(NEW)->>'id')::uuid; exception when others then v_source_id := null; end;
  begin v_row_pk := (to_jsonb(NEW)->>'id'); exception when others then v_row_pk := null; end;
  begin v_job_id := (to_jsonb(NEW)->>'job_id')::uuid; exception when others then v_job_id := null; end;
  begin v_report_type := (to_jsonb(NEW)->>'report_type'); exception when others then v_report_type := null; end;
  begin v_title := (to_jsonb(NEW)->>'title'); exception when others then v_title := null; end;

  -- Determine next version number for this source row within this table
  select coalesce(max(version), 0) + 1 into v_next_version
  from neta_ops.backup_reports br
  where br.source_schema = tg_table_schema
    and br.source_table = tg_table_name
    and (v_source_id is not distinct from br.source_id);

  insert into neta_ops.backup_reports(
    source_schema, source_table, source_id, row_pk, action, job_id, report_type, title, data, version, edited_by
  ) values (
    tg_table_schema, tg_table_name, v_source_id, v_row_pk, lower(tg_op), v_job_id, v_report_type, v_title, v_payload_new, v_next_version, auth.uid()
  );

  return NEW;
end; $$;


