--
-- Name: get_deleted_reports(); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.get_deleted_reports() RETURNS TABLE(table_name text, report_type text, id uuid, job_id uuid, user_id uuid, identifier text, deleted_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
DECLARE
    table_rec RECORD;
    query_text TEXT;
    result_query TEXT := '';
BEGIN
    -- Build dynamic query for each table that exists and has deleted_at column
    FOR table_rec IN 
        SELECT t.table_name, 
               CASE 
                   WHEN t.table_name = 'low_voltage_switch_reports' THEN 'Low Voltage Switch Report'
                   WHEN t.table_name = 'voltage_potential_transformer_mts_reports' THEN 'Voltage Potential Transformer MTS Report'
                   WHEN t.table_name = 'medium_voltage_switch_oil_reports' THEN 'Medium Voltage Switch Oil Report'
                   WHEN t.table_name = 'two_small_dry_type_xfmr_mts_reports' THEN 'Two Small Dry Type Transformer MTS Report'
                   WHEN t.table_name = 'medium_voltage_vlf_mts_reports' THEN 'Medium Voltage VLF MTS Report'
                   WHEN t.table_name = 'metal_enclosed_busway_reports' THEN 'Metal Enclosed Busway Report'
                   WHEN t.table_name = 'tandelta_mts_reports' THEN 'Tan Delta MTS Report'
                   WHEN t.table_name = 'current_transformer_test_ats_reports' THEN 'Current Transformer Test ATS Report'
                   WHEN t.table_name = 'medium_voltage_motor_starter_mts_reports' THEN 'Medium Voltage Motor Starter MTS Report'
                   WHEN t.table_name = 'potential_transformer_ats_reports' THEN 'Potential Transformer ATS Report'
                   WHEN t.table_name = 'switchgear_reports' THEN 'Switchgear Report'
                   WHEN t.table_name = 'large_dry_type_transformer_mts_reports' THEN 'Large Dry Type Transformer MTS Report'
                   WHEN t.table_name = 'medium_voltage_circuit_breaker_reports' THEN 'Medium Voltage Circuit Breaker Report'
                   WHEN t.table_name = 'tandelta_reports' THEN 'Tan Delta Report'
                   WHEN t.table_name = 'liquid_xfmr_visual_mts_reports' THEN 'Liquid Transformer Visual MTS Report'
                   WHEN t.table_name = 'low_voltage_panelboard_small_breaker_reports' THEN 'Low Voltage Panelboard Small Breaker Report'
                   WHEN t.table_name = 'switchgear_panelboard_mts_reports' THEN 'Switchgear Panelboard MTS Report'
                   WHEN t.table_name = 'current_transformer_test_mts_reports' THEN 'Current Transformer Test MTS Report'
                   WHEN t.table_name = 'large_transformer_reports' THEN 'Large Transformer Report'
                   WHEN t.table_name = 'panelboard_reports' THEN 'Panelboard Report'
                   WHEN t.table_name = 'automatic_transfer_switch_ats_reports' THEN 'Automatic Transfer Switch ATS Report'
                   WHEN t.table_name = 'transformer_reports' THEN 'Transformer Report'
                   WHEN t.table_name = 'medium_voltage_circuit_breaker_mts_reports' THEN 'Medium Voltage Circuit Breaker MTS Report'
                   WHEN t.table_name = 'low_voltage_circuit_breaker_thermal_magnetic_mts_reports' THEN 'Low Voltage Circuit Breaker Thermal Magnetic MTS Report'
                   WHEN t.table_name = 'two_small_dry_type_xfmr_ats_reports' THEN 'Two Small Dry Type Transformer ATS Report'
                   ELSE INITCAP(REPLACE(t.table_name, '_', ' '))
               END as report_type_name
        FROM information_schema.tables t
        JOIN information_schema.columns c ON c.table_name = t.table_name AND c.table_schema = t.table_schema
        WHERE t.table_schema = 'neta_ops' 
        AND t.table_name LIKE '%_reports'
        AND c.column_name = 'deleted_at'
    LOOP
        -- Build query for this table
        query_text := format('
            SELECT 
                %L as table_name,
                %L as report_type,
                id,
                job_id,
                user_id,
                COALESCE(id::text, ''Unnamed'') as identifier,
                deleted_at,
                created_at
            FROM neta_ops.%I 
            WHERE deleted_at IS NOT NULL',
            table_rec.table_name,
            table_rec.report_type_name,
            table_rec.table_name
        );
        
        -- Add UNION ALL if not the first query
        IF result_query != '' THEN
            result_query := result_query || ' UNION ALL ';
        END IF;
        
        result_query := result_query || query_text;
    END LOOP;
    
    -- Execute the dynamic query
    IF result_query != '' THEN
        RETURN QUERY EXECUTE result_query;
    END IF;
END;
$$;


--
-- Name: get_maintenance_due_equipment(integer); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.get_maintenance_due_equipment(days_threshold integer DEFAULT 30) RETURNS TABLE(id uuid, name text, next_maintenance_date date, days_until_maintenance integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    e.id,
    e.name,
    e.next_maintenance_date,
    (e.next_maintenance_date - CURRENT_DATE) AS days_until_maintenance
  FROM 
    neta_ops.equipment e
  WHERE 
    e.next_maintenance_date IS NOT NULL
    AND e.next_maintenance_date - CURRENT_DATE <= days_threshold
    AND e.next_maintenance_date >= CURRENT_DATE
  ORDER BY 
    e.next_maintenance_date;
END;
$$;


