--
-- Name: parse_equipment_date(text); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.parse_equipment_date(date_str text) RETURNS date
    LANGUAGE plpgsql
    AS $_$
DECLARE
  parsed_date DATE;
BEGIN
  IF date_str IS NULL OR date_str = '' OR date_str = 'N/A' THEN
    RETURN NULL;
  END IF;
  
  -- Try different date formats
  BEGIN
    -- Format: M/D/YYYY or MM/DD/YYYY
    IF date_str ~ '^\d{1,2}/\d{1,2}/\d{4}$' THEN
      parsed_date := TO_DATE(date_str, 'MM/DD/YYYY');
      RETURN parsed_date;
    END IF;
    
    -- Format: M/YYYY (like "2/2022")
    IF date_str ~ '^\d{1,2}/\d{4}$' THEN
      parsed_date := TO_DATE('01/' || date_str, 'DD/MM/YYYY');
      RETURN parsed_date;
    END IF;
    
    -- Format: YYYY-MM-DD
    IF date_str ~ '^\d{4}-\d{2}-\d{2}$' THEN
      parsed_date := date_str::DATE;
      RETURN parsed_date;
    END IF;
    
    -- Try generic parsing
    parsed_date := date_str::DATE;
    RETURN parsed_date;
  EXCEPTION
    WHEN OTHERS THEN
      RETURN NULL;
  END;
END;
$_$;


--
-- Name: restore_report(text, uuid, uuid); Type: FUNCTION; Schema: neta_ops; Owner: -
--

CREATE FUNCTION neta_ops.restore_report(table_name text, report_id uuid, user_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
    result INTEGER := 0;
BEGIN
    -- Validate table name to prevent SQL injection
    IF table_name NOT IN (
        'low_voltage_switch_reports',
        'voltage_potential_transformer_mts_reports',
        'medium_voltage_switch_oil_reports',
        'two_small_dry_type_xfmr_mts_reports',
        'medium_voltage_vlf_mts_reports',
        'metal_enclosed_busway_reports',
        'tandelta_mts_reports',
        'current_transformer_test_ats_reports',
        'medium_voltage_motor_starter_mts_reports',
        'potential_transformer_ats_reports',
        'switchgear_reports',
        'large_dry_type_transformer_mts_reports',
        'medium_voltage_circuit_breaker_reports',
        'tandelta_reports',
        'liquid_xfmr_visual_mts_reports',
        'low_voltage_panelboard_small_breaker_reports',
        'switchgear_panelboard_mts_reports',
        'current_transformer_test_mts_reports',
        'large_transformer_reports',
        'panelboard_reports',
        'automatic_transfer_switch_ats_reports',
        'transformer_reports',
        'medium_voltage_circuit_breaker_mts_reports',
        'low_voltage_circuit_breaker_thermal_magnetic_mts_reports',
        'two_small_dry_type_xfmr_ats_reports',
        'low_voltage_cable_test_20sets',
        'low_voltage_cable_test_12sets',
        'low_voltage_cable_test_3sets',
        'low_voltage_circuit_breaker_electronic_trip_ats',
        'low_voltage_circuit_breaker_thermal_magnetic_ats_reports',
        'low_voltage_circuit_breaker_electronic_trip_mts_reports',
        'medium_voltage_switch_sf6_reports',
        'oil_analysis_reports',
        'oil_inspection_reports',
        'relay_test_reports',
        'cable_hipot_reports',
        'large_dry_type_transformer_reports'
    ) THEN
        RAISE EXCEPTION 'Invalid table name: %', table_name;
    END IF;

    -- Execute the restore
    EXECUTE format('
        UPDATE neta_ops.%I 
        SET deleted_at = NULL, updated_at = NOW()
        WHERE id = $1 AND user_id = $2 AND deleted_at IS NOT NULL
    ', table_name) USING report_id, user_id;
    
    GET DIAGNOSTICS result = ROW_COUNT;
    RETURN result > 0;
END;
$_$;


