        NULL;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: set_opportunity_created_date(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_opportunity_created_date() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Only set on INSERT, not UPDATE
    IF TG_OP = 'INSERT' THEN
        -- Set to today at noon UTC to prevent timezone shifts when displaying dates
        NEW.opportunity_created_date := (CURRENT_DATE || ' 12:00:00+00')::TIMESTAMP WITH TIME ZONE;
    END IF;
    RETURN NEW;
END;
$$;


