    day_of_week integer NOT NULL,
    start_time time without time zone NOT NULL,
    end_time time without time zone NOT NULL,
    portal_type text NOT NULL,
    division text,
    recurring boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT availability_time_check CHECK ((start_time < end_time)),
    CONSTRAINT technician_availability_day_of_week_check CHECK (((day_of_week >= 0) AND (day_of_week <= 6))),
    CONSTRAINT technician_availability_portal_type_check CHECK ((portal_type = ANY (ARRAY['neta'::text, 'lab'::text, 'scavenger'::text])))
);


--
-- Name: available_technicians; Type: VIEW; Schema: common; Owner: -
--

CREATE VIEW common.available_technicians AS
 SELECT ua.user_id,
    COALESCE((u.raw_user_meta_data ->> 'name'::text), (u.email)::text) AS full_name,
    u.email,
    ua.division,
    ua.portal_type,
    ua.day_of_week,
    ua.start_time,
    ua.end_time
   FROM (common.technician_availability ua
     JOIN auth.users u ON ((u.id = ua.user_id)));


