--
-- Name: customer_satisfaction_scores; Type: MATERIALIZED VIEW; Schema: common; Owner: -
--

CREATE MATERIALIZED VIEW common.customer_satisfaction_scores AS
 SELECT c.id AS customer_id,
    c.company_name,
    COALESCE(avg(cs.satisfaction_score), (0)::numeric) AS avg_score,
    count(cs.id) FILTER (WHERE (cs.status = 'completed'::text)) AS completed_surveys,
    count(cs.id) AS total_surveys,
    max(cs.completed_at) AS last_survey_date
   FROM (common.customers c
     LEFT JOIN common.customer_surveys cs ON ((c.id = cs.customer_id)))
  GROUP BY c.id, c.company_name
  WITH NO DATA;


--
-- Name: MATERIALIZED VIEW customer_satisfaction_scores; Type: COMMENT; Schema: common; Owner: -
--

COMMENT ON MATERIALIZED VIEW common.customer_satisfaction_scores IS 'Aggregated customer satisfaction scores';


