-- Name: TABLE system_config; Type: COMMENT; Schema: common; Owner: -
--

COMMENT ON TABLE common.system_config IS 'Stores system-wide configuration settings, including encryption keys.';


--
-- Name: encryption_status; Type: VIEW; Schema: common; Owner: -
--

CREATE VIEW common.encryption_status AS
 SELECT 'encryptionSettings'::text AS config_name,
        CASE
            WHEN (EXISTS ( SELECT 1
               FROM common.system_config
              WHERE (system_config.key = 'encryptionSettings'::text))) THEN 'Active'::text
            ELSE 'Not Configured'::text
        END AS status,
    ( SELECT (system_config.value ->> 'created'::text)
           FROM common.system_config
          WHERE (system_config.key = 'encryptionSettings'::text)) AS key_created_date,
    (( SELECT (system_config.value ->> 'rotationIntervalDays'::text)
           FROM common.system_config
          WHERE (system_config.key = 'encryptionSettings'::text)))::integer AS rotation_interval,
    ( SELECT jsonb_array_length((system_config.value -> 'previousKeys'::text)) AS jsonb_array_length
           FROM common.system_config
          WHERE (system_config.key = 'encryptionSettings'::text)) AS previous_keys_count;


