--
-- Name: message_retention_stats; Type: VIEW; Schema: common; Owner: -
--

CREATE VIEW common.message_retention_stats AS
 SELECT count(*) AS total_messages,
    count(*) FILTER (WHERE (created_at > (now() - '24:00:00'::interval))) AS recent_messages,
    count(*) FILTER (WHERE ((created_at <= (now() - '24:00:00'::interval)) AND (created_at >= ( SELECT ((system_config.value ->> 'timestamp'::text))::timestamp with time zone AS timestamptz
           FROM common.system_config
          WHERE (system_config.key = 'message_retention_start'::text))))) AS pending_deletion,
    count(*) FILTER (WHERE (created_at < ( SELECT ((system_config.value ->> 'timestamp'::text))::timestamp with time zone AS timestamptz
           FROM common.system_config
          WHERE (system_config.key = 'message_retention_start'::text)))) AS preserved_old_messages,
    min(created_at) AS oldest_message_time,
    max(created_at) AS newest_message_time
   FROM common.chat_messages;


