    end_time time without time zone NOT NULL,
    status text DEFAULT 'scheduled'::text,
    notes text,
    portal_type text NOT NULL,
    division text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    created_by uuid,
    CONSTRAINT assignment_time_check CHECK ((start_time < end_time)),
    CONSTRAINT technician_assignments_portal_type_check CHECK ((portal_type = ANY (ARRAY['neta'::text, 'lab'::text, 'scavenger'::text]))),
    CONSTRAINT technician_assignments_status_check CHECK ((status = ANY (ARRAY['scheduled'::text, 'in-progress'::text, 'completed'::text, 'cancelled'::text])))
);


