    end_time time without time zone,
    reason text,
    portal_type text NOT NULL,
    division text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT exception_time_check CHECK (((is_available = false) OR ((is_available = true) AND (start_time IS NOT NULL) AND (end_time IS NOT NULL) AND (start_time < end_time)))),
    CONSTRAINT technician_exceptions_portal_type_check CHECK ((portal_type = ANY (ARRAY['neta'::text, 'lab'::text, 'scavenger'::text])))
);


