);


--
-- Name: technicians; Type: VIEW; Schema: common; Owner: -
--

CREATE VIEW common.technicians AS
 SELECT id,
    email,
    (raw_user_meta_data ->> 'firstName'::text) AS first_name,
    (raw_user_meta_data ->> 'lastName'::text) AS last_name,
    (((raw_user_meta_data ->> 'firstName'::text) || ' '::text) || (raw_user_meta_data ->> 'lastName'::text)) AS name,
    (raw_app_meta_data ->> 'role'::text) AS role
   FROM auth.users;


