--
-- Name: v_active_job_requisitions; Type: VIEW; Schema: common; Owner: -
--

CREATE VIEW common.v_active_job_requisitions AS
 SELECT id,
    title,
    department,
    location,
    employment_type,
    salary_range_min,
    salary_range_max,
    status,
    priority,
    requisition_number,
    created_at,
    updated_at,
    created_by,
    number_of_positions
   FROM common.job_requisitions
  WHERE ((deleted_at IS NULL) AND ((status)::text <> ALL (ARRAY[('closed'::character varying)::text, ('cancelled'::character varying)::text])));


--
-- Name: v_pending_approval_requisitions; Type: VIEW; Schema: common; Owner: -
--

CREATE VIEW common.v_pending_approval_requisitions AS
 SELECT id,
    title,
    department,
    location,
    employment_type,
    priority,
    requisition_number,
    created_by,
    submitted_for_approval_at,
    created_at
   FROM common.job_requisitions
  WHERE ((deleted_at IS NULL) AND ((status)::text = 'pending_approval'::text))
  ORDER BY submitted_for_approval_at DESC, priority DESC;


--
-- Name: v_posted_job_requisitions; Type: VIEW; Schema: common; Owner: -
--

CREATE VIEW common.v_posted_job_requisitions AS
 SELECT id,
    title,
    department,
    location,
    employment_type,
    salary_range_min,
    salary_range_max,
    description,
    requirements,
    requisition_number,
    posted_at,
    application_deadline,
    posting_end_date
   FROM common.job_requisitions
  WHERE ((deleted_at IS NULL) AND ((status)::text = 'posted'::text) AND ((posting_end_date IS NULL) OR (posting_end_date >= CURRENT_DATE)))
  ORDER BY posted_at DESC;


