    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    employee_id uuid NOT NULL,
    leave_type_id uuid NOT NULL,
    from_date date NOT NULL,
    to_date date NOT NULL,
    half_day boolean DEFAULT false,
    half_day_date date,
    total_leave_days numeric(5,2) NOT NULL,
    reason text,
    status text DEFAULT 'Open'::text,
    approved_by uuid,
    approved_on timestamp with time zone,
    rejection_reason text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid,
    CONSTRAINT leave_applications_status_check CHECK ((status = ANY (ARRAY['Open'::text, 'Approved'::text, 'Rejected'::text, 'Cancelled'::text])))
);


--
-- Name: leave_types; Type: TABLE; Schema: hr; Owner: -
--

CREATE TABLE hr.leave_types (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    name text NOT NULL,
    max_days integer NOT NULL,
    allow_encashment boolean DEFAULT false,
    is_carry_forward boolean DEFAULT false,
    is_optional_leave boolean DEFAULT false,
    description text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


