-- Name: salary_slips; Type: TABLE; Schema: hr; Owner: -
--

CREATE TABLE hr.salary_slips (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    employee_id uuid NOT NULL,
    salary_slip_number text NOT NULL,
    salary_month date NOT NULL,
    gross_pay numeric(10,2) NOT NULL,
    total_deduction numeric(10,2) DEFAULT 0,
    net_pay numeric(10,2) GENERATED ALWAYS AS ((gross_pay - total_deduction)) STORED,
    status text DEFAULT 'Draft'::text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid,
    CONSTRAINT salary_slips_status_check CHECK ((status = ANY (ARRAY['Draft'::text, 'Submitted'::text, 'Paid'::text])))
);


--
-- Name: v_active_job_requisitions; Type: VIEW; Schema: hr; Owner: -
--

CREATE VIEW hr.v_active_job_requisitions AS
 SELECT id,
    title,
    department,
    location,
    employment_type,
    salary_range_min,
    salary_range_max,
    status,
    priority,
    requisition_number,
    created_at,
    updated_at,
    created_by,
    number_of_positions
   FROM hr.job_requisitions
  WHERE ((deleted_at IS NULL) AND ((status)::text <> ALL (ARRAY[('closed'::character varying)::text, ('cancelled'::character varying)::text])));


--
-- Name: v_pending_approval_requisitions; Type: VIEW; Schema: hr; Owner: -
--

CREATE VIEW hr.v_pending_approval_requisitions AS
 SELECT id,
    title,
    department,
    location,
    employment_type,
    priority,
    requisition_number,
    created_by,
    submitted_for_approval_at,
    created_at
   FROM hr.job_requisitions
  WHERE ((deleted_at IS NULL) AND ((status)::text = 'pending_approval'::text))
  ORDER BY submitted_for_approval_at DESC, priority DESC;


--
-- Name: v_posted_job_requisitions; Type: VIEW; Schema: hr; Owner: -
--

CREATE VIEW hr.v_posted_job_requisitions AS
 SELECT id,
    title,
    department,
    location,
    employment_type,
    salary_range_min,
    salary_range_max,
    description,
    requirements,
    requisition_number,
    posted_at,
    application_deadline,
    posting_end_date
   FROM hr.job_requisitions
  WHERE ((deleted_at IS NULL) AND ((status)::text = 'posted'::text) AND ((posting_end_date IS NULL) OR (posting_end_date >= CURRENT_DATE)))
  ORDER BY posted_at DESC;


