--

CREATE VIEW neta_ops.available_technicians AS
 SELECT ua.user_id,
    COALESCE((u.raw_user_meta_data ->> 'name'::text), (u.email)::text) AS full_name,
    u.email,
    ua.division,
    ua.portal_type,
    ua.day_of_week,
    ua.start_time,
    ua.end_time
   FROM (neta_ops.technician_availability ua
     JOIN auth.users u ON ((u.id = ua.user_id)));


