);


--
-- Name: quality_metrics; Type: TABLE; Schema: neta_ops; Owner: -
--

CREATE TABLE neta_ops.quality_metrics (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    equipment_id uuid NOT NULL,
    metric_name text NOT NULL,
    metric_value numeric(10,2) NOT NULL,
    unit text,
    date_recorded date DEFAULT CURRENT_DATE NOT NULL,
    target_value numeric(10,2),
    lower_threshold numeric(10,2),
    upper_threshold numeric(10,2),
    status text GENERATED ALWAYS AS (
CASE
    WHEN (metric_value < lower_threshold) THEN 'below-threshold'::text
    WHEN (metric_value > upper_threshold) THEN 'above-threshold'::text
    ELSE 'within-threshold'::text
END) STORED,
    notes text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    created_by uuid
);


