--
-- Name: admin_notifications; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.admin_notifications (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    type text NOT NULL,
    message text NOT NULL,
    is_read boolean DEFAULT false NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: after_action_reports; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.after_action_reports (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    job_id uuid NOT NULL,
    report_type text NOT NULL,
    status text DEFAULT 'draft'::text NOT NULL,
    technician_name text,
    report_date date,
    project_job_number text,
    client_site_name text,
    phase_scope_completed text,
    crew_size_roles text,
    safety_incident boolean DEFAULT false,
    incident_description text,
    near_misses_hazards text,
    delays_encountered text,
    scope_changes text,
    equipment_issues text,
    coordination_issues text,
    time_allocation jsonb DEFAULT '[]'::jsonb,
    consumables_used text,
    materials_purchased_in_field text,
    rental_equipment_used text,
    technician_sign_off_name text,
    technician_confirmed boolean DEFAULT false,
    technician_submission_timestamp timestamp with time zone,
    estimated_hours numeric(10,2),
    total_hours_worked numeric(10,2),
    variance_hours numeric(10,2),
    crew_size_roles_confirmed text,
    labor_cost_total numeric(12,2),
    materials_cost_total numeric(12,2),
    rental_cost_total numeric(12,2),
    finalized_project_cost numeric(12,2),
    adjustments_to_technician_report text,
    notes_for_project_manager text,
    admin_name text,
    admin_submission_timestamp timestamp with time zone,
    created_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT after_action_reports_report_type_check CHECK ((report_type = ANY (ARRAY['technician_progress'::text, 'admin_closeout'::text]))),
    CONSTRAINT after_action_reports_status_check CHECK ((status = ANY (ARRAY['draft'::text, 'submitted'::text, 'approved'::text, 'rejected'::text])))
);


--
-- Name: android_lab_customers; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.android_lab_customers AS
 SELECT id,
    name,
    company_name,
    email,
    NULL::text AS phone,
    NULL::text AS address,
    NULL::text AS city,
    NULL::text AS state,
    NULL::text AS zip_code,
    username,
    user_id,
    created_at,
    updated_at
   FROM lab_ops.lab_customers;


--
-- Name: android_lab_jobs; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.android_lab_jobs AS
 SELECT id,
    job_number,
    title,
    status,
    division,
    customer_id,
    description,
    start_date,
    due_date,
    budget,
    priority,
    notes,
    user_id,
    created_at,
    updated_at
   FROM lab_ops.lab_jobs;


