    vendor_id uuid NOT NULL,
    title text NOT NULL,
    description text,
    start_date date,
    end_date date,
    value numeric(12,2) DEFAULT 0,
    status text DEFAULT 'active'::text,
    renewal_terms text,
    document_url text,
