-- Name: one_on_one_checkins one_on_one_checkins_delete_manager_chain; Type: POLICY; Schema: common; Owner: -
--

CREATE POLICY one_on_one_checkins_delete_manager_chain ON common.one_on_one_checkins FOR DELETE USING ((EXISTS ( WITH RECURSIVE ancestors AS (
         SELECT a.reports_to_profile_id AS mgr
           FROM common.org_chart_assignments a
          WHERE ((a.profile_id = one_on_one_checkins.employee_id) AND (a.reports_to_profile_id IS NOT NULL))
        UNION ALL
         SELECT o.reports_to_profile_id
           FROM (common.org_chart_assignments o
             JOIN ancestors anc ON ((o.profile_id = anc.mgr)))
          WHERE (o.reports_to_profile_id IS NOT NULL)
        )
 SELECT 1
   FROM ancestors
  WHERE (ancestors.mgr = auth.uid()))));


