CREATE POLICY "Technicians can update equipment calibration dates" ON neta_ops.equipment FOR UPDATE USING (((auth.uid() IS NOT NULL) AND ((lower(COALESCE(((auth.jwt() -> 'user_metadata'::text) ->> 'role'::text), ''::text)) = ANY (ARRAY['admin'::text, 'super admin'::text, 'manager'::text, 'supervisor'::text, 'technician'::text, 'neta technician'::text, 'field technician'::text])) OR (COALESCE(((auth.jwt() -> 'user_metadata'::text) -> 'permissions'::text), '[]'::jsonb) ? 'equipment_manage'::text) OR (COALESCE(((auth.jwt() -> 'user_metadata'::text) -> 'permissions'::text), '[]'::jsonb) ? 'equipment_view'::text)))) WITH CHECK (((auth.uid() IS NOT NULL) AND ((lower(COALESCE(((auth.jwt() -> 'user_metadata'::text) ->> 'role'::text), ''::text)) = ANY (ARRAY['admin'::text, 'super admin'::text, 'manager'::text, 'supervisor'::text, 'technician'::text, 'neta technician'::text, 'field technician'::text])) OR (COALESCE(((auth.jwt() -> 'user_metadata'::text) -> 'permissions'::text), '[]'::jsonb) ? 'equipment_manage'::text) OR (COALESCE(((auth.jwt() -> 'user_metadata'::text) -> 'permissions'::text), '[]'::jsonb) ? 'equipment_view'::text))));


